include <cstdint>   
#include <chrono>   
//返回经过的纳秒数   
uint64_t timeWithChrono() { using namespace std::chrono; auto start \(=\) steady_clock::now(); //运行一些代码 auto end \(=\) steady_clock::now(); uint64_t delta \(=\) duration_cast<nanoseconds>(end - start).count(); return delta;   
}

// foo不会对字符串创建进行基准测试  
